SELECT oPerson.`HASPERSONNAME` AS oPerson_hasPersonName FROM `FIBEN`.`FINANCIALSERVICEACCOUNT` oFinancialServiceAccount INNER JOIN `FIBEN`.`PERSON` oPerson ON oFinancialServiceAccount.`ISOWNEDBY`=oPerson.`PERSONID` WHERE oPerson.`HASPERSONNAME` NOT IN (SELECT oInnerPerson.`HASPERSONNAME` AS oInnerPerson_hasPersonName FROM `FIBEN`.`SECURITIESTRANSACTION` oInnerSecuritiesTransaction INNER JOIN `FIBEN`.`FINANCIALSERVICEACCOUNT` innerFinancialServiceAccount1 ON oInnerSecuritiesTransaction.`ISFACILITATEDBY`=innerFinancialServiceAccount1.`FINANCIALSERVICEACCOUNTID` INNER JOIN `FIBEN`.`PERSON` oInnerPerson ON innerFinancialServiceAccount1.`ISOWNEDBY`=oInnerPerson.`PERSONID` INNER JOIN `FIBEN`.`LISTEDSECURITY` oInnerListedSecurity ON oInnerSecuritiesTransaction.`REFERSTO`=oInnerListedSecurity.`LISTEDSECURITYID` WHERE oInnerSecuritiesTransaction.`HASTYPE` = '1' AND oInnerListedSecurity.`HASLEGALNAME` = 'Alphabet Inc.' AND oInnerSecuritiesTransaction.`HASSETTLEMENTDATE` u003e= '2019-01-01 00:00:00.000' AND oInnerSecuritiesTransaction.`HASSETTLEMENTDATE` u003c= '2019-12-31 23:59:00.000')